package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.MalformedJsonException;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;

class JsonParserTest {

  @Test
  void parseReader_validJson_consumesEntireDocument() throws Exception {
    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);
    JsonElement element = JsonParser.parseReader(reader);
    assertNotNull(element);
    assertFalse(element.isJsonNull());
  }

  @Test
  void parseReader_emptyJson_returnsJsonNull() throws Exception {
    String json = "null";
    Reader reader = new StringReader(json);
    JsonElement element = JsonParser.parseReader(reader);
    assertNotNull(element);
    assertTrue(element.isJsonNull());
  }

  @Test
  void parseReader_partialConsumption_throwsJsonSyntaxException() throws Exception {
    // We mock JsonReader to simulate peek returning a token other than END_DOCUMENT
    Reader reader = mock(Reader.class);
    JsonReader jsonReader = mock(JsonReader.class);

    // Spy JsonParser to mock static parseReader(JsonReader) method
    // Since parseReader(JsonReader) is static, we cannot spy easily without PowerMockito
    // Instead, we create a subclass to override parseReader(JsonReader)
    class JsonParserSubclass extends JsonParser {
      static JsonElement parseReader(JsonReader jr) throws IOException {
        return new JsonPrimitive("value");
      }
    }

    // We cannot replace the static call inside parseReader(Reader)
    // So we test this scenario by feeding JSON that leaves trailing data

    String json = "{\"key\":\"value\"} trailing";
    Reader stringReader = new StringReader(json);

    JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> {
      JsonParser.parseReader(stringReader);
    });
    assertEquals("Did not consume the entire document.", ex.getMessage());
  }

  @Test
  void parseReader_malformedJson_throwsJsonSyntaxException() {
    String json = "{malformed json";
    Reader reader = new StringReader(json);

    JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> {
      JsonParser.parseReader(reader);
    });
    assertNotNull(ex.getCause());
    assertTrue(ex.getCause() instanceof MalformedJsonException);
  }

  @Test
  void parseReader_ioException_throwsJsonIOException() throws IOException {
    Reader reader = mock(Reader.class);
    when(reader.read(any(char[].class), anyInt(), anyInt())).thenThrow(new IOException("io exception"));

    JsonIOException ex = assertThrows(JsonIOException.class, () -> {
      JsonParser.parseReader(reader);
    });
    assertNotNull(ex.getCause());
    assertTrue(ex.getCause() instanceof IOException);
  }

  @Test
  void parseReader_numberFormatException_throwsJsonSyntaxException() {
    // To simulate NumberFormatException thrown by parseReader(JsonReader),
    // we create a subclass with overridden static method parseReader(JsonReader)
    // But static methods cannot be overridden, so we simulate by feeding JSON that triggers it
    // This is tricky without modifying source, so we simulate via reflection

    // Use reflection to invoke private static parseReader(JsonReader) with JsonReader that throws NumberFormatException

    try {
      JsonReader jsonReader = mock(JsonReader.class);
      when(jsonReader.peek()).thenReturn(JsonToken.NUMBER);
      when(jsonReader.nextString()).thenThrow(new NumberFormatException("number format"));

      java.lang.reflect.Method parseReaderMethod = JsonParser.class.getDeclaredMethod("parseReader", JsonReader.class);
      parseReaderMethod.setAccessible(true);

      Executable executable = () -> {
        parseReaderMethod.invoke(null, jsonReader);
      };

      Throwable thrown = assertThrows(Exception.class, executable);
      Throwable cause = thrown.getCause();
      assertNotNull(cause);
      assertTrue(cause instanceof JsonSyntaxException);
      assertTrue(cause.getCause() instanceof NumberFormatException);
    } catch (NoSuchMethodException e) {
      fail("parseReader(JsonReader) method not found");
    }
  }
}
